```class Solution {
    public int distinctSequences(int n) {
        int result = 1;
        for (int i = 1; i <= n; i++) {
            result *= (i % 2 == 0 ? 2 : 1) * (i % 3 == 0 ? 2 : 1) * (i % 5 == 0 ? 2 : 1);
        }
        return result % (1000000007);
    }
}
